                cin.ignore(numeric_limits<streamsize>::max(), '\n'); // Ignores the rest of the input until a newline character is found
                cout << "Invalid choice. Please try again.\n";
                // Pause to allow the user to read the message
                system("pause"); // Windows-specific. On Unix/Linux, use something like "cin.ignore(); cin.get();" for a pause.
