void splitBill(const vector<string>& orders, const float payable) {
    int numPeople = orders.size();
    cout << "\n\tSplitting the bill among " << numPeople << " people:" << endl;

    float share = payable / numPeople;

    cout << "\n\tEach person's share: P" << share << endl;

    // Display individual orders
    for (int i = 0; i < numPeople; ++i) {
        cout << "\n\tOrders for Person " << i + 1 << ":" << endl;
        cout << "\t- " << orders[i] << endl;

        // Ask for payment
        float individualPayment;
        cout << "\n\tEnter the amount of money Person " << i + 1 << " will pay: P";
        cin >> individualPayment;

        float change = individualPayment - share;
        cout << "\n\tChange for Person " << i + 1 << ": P" << change << endl;
    }
}

